    out_piece = out_piece or (pieces if len(pieces) == 1 else None)
    assert out_piece is not None
    look = "".join(f"(?=.{{{x}}}1)" for x in clear)
    if frm < to:
        mid = to - frm - 1
        tail = 63 - to
        pat = (
            rf"(?m)^S {look}(.{{{frm}}})([{pieces}])(.{{{mid}}})"
            rf"([{target}])(.{{{tail}}}) ([KQkq.]{{4}}) ((?:-|[a-h][36]))$"
        )
        repl = (
            rf"\g<0>\nF \g<1>1\g<3>{out_piece}\g<5> "
            rf"\g<6> {ep} {flags}"
        )
    else:
        mid = frm - to - 1
        tail = 63 - frm
        pat = (
            rf"(?m)^S {look}(.{{{to}}})([{target}])(.{{{mid}}})"
            rf"([{pieces}])(.{{{tail}}}) ([KQkq.]{{4}}) ((?:-|[a-h][36]))$"
