            if pat not in seen:
                add_pair(rules, pat, "")
                seen.add(pat)

    # Apply castling-right removal flags.
    specs = [
        ("K", 0, "A"),
        ("Q", 1, "B"),
        ("k", 2, "C"),
        ("q", 3, "D"),
    ]
    for ch, pos, flag in specs:
        before = "." * pos
        after = "." * (3 - pos)
        # Target the exact character position in the four-character mask.
        add_pair(
            rules,
            rf"(?m)^(F .{{64}} {before}){ch}(.{{{3 - pos}}} (?:-|[a-h][36]) [A-DGH]*{flag}[A-DGH]*)$",
            rf"\g<1>.\g<2>",
        )

    add_pair(rules, r"(?m)^(F .{64} [KQkq.]{4} (?:-|[a-h][36])) [A-DGH]*$", r"\g<1>")
    add_pair(rules, r"(?m)^S .*$\n?", "")

    add_pair(
        rules,
        r"(?m)^F (.{8})(.{8})(.{8})(.{8})(.{8})(.{8})(.{8})(.{8}) ([KQkq.]{4}) ((?:-|[a-h][36]))$",
        r"\g<1>/\g<2>/\g<3>/\g<4>/\g<5>/\g<6>/\g<7>/\g<8> b \g<9> \g<10> 0 0",
    )

    for fixed, text in sorted(((v, k) for k, v in masks.items()), key=lambda x: -len(x[0])):
        add_pair(rules, rf"(?m) b {re.escape(fixed)} ", rf" b {text} ")

    for d, s in [
        ("8", "11111111"), ("7", "1111111"), ("6", "111111"),
        ("5", "11111"), ("4", "1111"), ("3", "111"),
        ("2", "11"),
    ]:
        add_pair(rules, s, d)

    add_pair(rules, r"\n\Z", "")

    with open("/app/re.json", "w") as f:
        json.dump(rules, f, separators=(",", ":"))

    print(len(rules))


